def _json_error(message, status=400):
    return jsonify({"ok": False, "error": message}), status

@app.post("/api/login")
def api_login():
    data = request.get_json(silent=True) or {}
    username = (data.get("username") or "").strip().lower()
    password = data.get("password") or ""
    otp = (data.get("otp") or "").strip()

    user = get_user(username)
    if not user or not check_password_hash(user["password_hash"], password):
        return _json_error("Invalid credentials.", 401)

    if user.get("mfa_enabled"):
        if not otp:
            return jsonify({"ok": False, "mfa_required": True, "message": "OTP required."}), 401
        if not verify_totp(user["mfa_secret"], otp):
            return _json_error("Invalid OTP.", 401)

    token = secrets.token_urlsafe(32)
    return jsonify({"ok": True, "token": token, "user": {"id": user["id"], "username": user["username"]}})

@app.post("/api/direct-login")
def api_direct_login():
    data = request.get_json(silent=True) or {}
    username = (data.get("username") or "").strip().lower()
    password = data.get("password") or ""
    api_key = data.get("api_key") or request.headers.get("X-API-Key") or ""

    user = get_user(username)
    if not user:
        return _json_error("Invalid credentials.", 401)

    if api_key and api_key != user.get("api_key"):
        return _json_error("Invalid API key.", 401)

    if not check_password_hash(user["password_hash"], password):
        return _json_error("Invalid credentials.", 401)

    token = secrets.token_urlsafe(32)
    return jsonify({
        "ok": True,
        "token": token,
        "mfa_skipped": True,
        "user": {"id": user["id"], "username": user["username"]},
    })

